    for i in range(len(loc_set)):
        index = dataset.index(loc_set[i])
        # print(rel_pro_set[i][x],rel_pro_set[x][i])
        cur_pro = fir_pro[index] * rel_pro_set[x][i]
        temp_list.append(cur_pro)
    sum_ = sum(temp_list)
    sed_pro = [i / sum_ for i in temp_list]
    return sed_pro
